import { Card, AddCard, TodoCard } from "./Card";

const TodoBox = function ({ handleModal, todos }) {
    return (
        <>
            <div className="todo-box">
                <Card cl={"add-card"}>
                    <AddCard handleModal={handleModal} />
                </Card>
                {todos.map((todo) => {
                    return (
                        <Card cl={"todo-card"}>
                            <TodoCard todo={todo} />
                        </Card>
                    );
                })}
            </div>
        </>
    );
};
export default TodoBox;
